package com.oyuki.wallet.controller; import com.oyuki.user.repository.UserRepository; import com.oyuki.wallet.entity.*; import com.oyuki.wallet.enums.WithdrawalStatus; import com.oyuki.wallet.repository.*; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import java.math.BigDecimal; import java.time.LocalDateTime; import java.util.*; @RestController @RequestMapping("/api/wallet") public class WalletController { private final SellerWalletRepository wallets;private final WithdrawalRequestRepository withdrawals;private final UserRepository users;public WalletController(SellerWalletRepository w,WithdrawalRequestRepository r,UserRepository u){wallets=w;withdrawals=r;users=u;} @GetMapping public Map<String,Object> wallet(Authentication a){return mapWallet(get((Long)a.getPrincipal()));} @PutMapping("/bank") public Map<String,Object> bank(Authentication a,@RequestBody Map<String,String>b){SellerWallet w=get((Long)a.getPrincipal());w.setBankName(b.get("bankName"));w.setAccountNumber(b.get("accountNumber"));w.setAccountName(b.get("accountName"));return mapWallet(wallets.save(w));} @PostMapping("/withdrawals") public ResponseEntity<?> withdraw(Authentication a,@RequestBody Map<String,String>b){SellerWallet w=get((Long)a.getPrincipal());BigDecimal amt=new BigDecimal(b.get("amount"));if(amt.signum()<=0||w.getAvailableBalance().compareTo(amt)<0)throw new IllegalArgumentException("Insufficient wallet balance");w.setAvailableBalance(w.getAvailableBalance().subtract(amt));w.setPendingBalance(w.getPendingBalance().add(amt));wallets.save(w);WithdrawalRequest r=WithdrawalRequest.builder().seller(w.getUser()).amount(amt).bankName(w.getBankName()).accountNumber(w.getAccountNumber()).accountName(w.getAccountName()).build();return ResponseEntity.status(201).body(mapWithdrawal(withdrawals.save(r)));} @GetMapping("/withdrawals/my") public List<Map<String,Object>> mine(Authentication a){return withdrawals.findAllBySeller_IdOrderByCreatedAtDesc((Long)a.getPrincipal()).stream().map(this::mapWithdrawal).toList();} @GetMapping("/admin/withdrawals") public List<Map<String,Object>> all(){return withdrawals.findAllByOrderByCreatedAtDesc().stream().map(this::mapWithdrawal).toList();} @PatchMapping("/admin/withdrawals/{id}") public Map<String,Object> process(@PathVariable Long id,@RequestBody Map<String,String>b){WithdrawalRequest r=withdrawals.findById(id).orElseThrow();WithdrawalStatus s=WithdrawalStatus.valueOf(b.get("status"));r.setStatus(s);r.setAdminNote(b.get("adminNote"));r.setProcessedAt(LocalDateTime.now());SellerWallet w=get(r.getSeller().getId());if(s==WithdrawalStatus.REJECTED){w.setPendingBalance(w.getPendingBalance().subtract(r.getAmount()));w.setAvailableBalance(w.getAvailableBalance().add(r.getAmount()));wallets.save(w);}else if(s==WithdrawalStatus.PAID){w.setPendingBalance(w.getPendingBalance().subtract(r.getAmount()));wallets.save(w);}return mapWithdrawal(withdrawals.save(r));} private SellerWallet get(Long uid){return wallets.findByUser_Id(uid).orElseGet(()->wallets.save(SellerWallet.builder().user(users.findById(uid).orElseThrow()).build()));} private Map<String,Object> mapWallet(SellerWallet w){Map<String,Object>m=new LinkedHashMap<>();m.put("availableBalance",w.getAvailableBalance());m.put("pendingBalance",w.getPendingBalance());m.put("bankName",w.getBankName());m.put("accountNumber",w.getAccountNumber());m.put("accountName",w.getAccountName());return m;} private Map<String,Object> mapWithdrawal(WithdrawalRequest r){Map<String,Object>m=new LinkedHashMap<>();m.put("id",r.getId());m.put("sellerName",r.getSeller().getFullName());m.put("amount",r.getAmount());m.put("bankName",r.getBankName());m.put("accountNumber",r.getAccountNumber());m.put("accountName",r.getAccountName());m.put("status",r.getStatus());m.put("adminNote",r.getAdminNote());m.put("createdAt",r.getCreatedAt());return m;} }